SELECT bs."in.comstock_building_type" AS comstock_building_type, date_trunc('month', date_add('second', -900, comstock_amy2018_r2_2025_ts_by_state.timestamp)) AS timestamp, count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) AS sample_count, (count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) * sum(bs.weight)) / CAST(sum(1) AS DECIMAL) AS units_count, sum(1) / CAST(count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) AS DECIMAL) AS rows_per_sample, sum(comstock_amy2018_r2_2025_ts_by_state."out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption", sum(comstock_amy2018_r2_2025_ts_by_state."out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption" FROM comstock_amy2018_r2_2025_ts_by_state JOIN comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs ON bs.bldg_id = comstock_amy2018_r2_2025_ts_by_state.bldg_id AND bs.state = comstock_amy2018_r2_2025_ts_by_state.state AND bs.upgrade = 0 AND comstock_amy2018_r2_2025_ts_by_state.upgrade = 1 AND comstock_amy2018_r2_2025_ts_by_state.state = 'CO' AND (comstock_amy2018_r2_2025_ts_by_state.bldg_id, comstock_amy2018_r2_2025_ts_by_state.state) IN (SELECT up.bldg_id, up.state FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS up WHERE up.upgrade IN (1, 2) AND up.applicability = true GROUP BY up.bldg_id, up.state HAVING count(distinct(up.upgrade)) = 2) AND bs.state = 'CO' WHERE bs.state = 'CO' GROUP BY 1, 2 ORDER BY 1, 2